<template>
    <div style="height: 50px"></div>
  <div>
    
    <n-space justify="center">
      <n-date-picker v-model:value="range" type="datetimerange" clearable  @update:value="onChange" />
      <n-button type="Primary" @click="getAutoData">查询</n-button>
      <n-select v-model:value="label_select" :options="options"   @update:value="handleUpdateTime" /> 
      <n-button type="Primary" @click="getLastAutoData" v-if = "is_query" >上一条</n-button>
      <n-button type="Primary" @click="getNextAutoData" v-if = "is_query" >下一条</n-button>
    </n-space>
    <action-charts :count="counts" style="top:30px;height:600%;width:100%;" :status="complateChartData"></action-charts>
  </div>
</template>


<script setup>
import { NDatePicker } from "naive-ui";
import dayjs from "dayjs";
import { computed,defineComponent, onMounted, ref, reactive } from "vue";
import { getSupportNum,getAutoDataAPI,getOneAutoDataAPI,getNextOneAutoDataAPI,getLastOneAutoDataAPI} from "@/api/request";
import { useMessage } from "naive-ui";
import ActionCharts from "../../state/components/action-echarts.vue";
import { measureMemory } from "vm";
const nMessage = useMessage();
const counts = ref(0);
const choose_id = ref(0)
//获取时间数据value
let endTime = Date.now();
let startTime = endTime - 24 * 60 * 60 * 1000 * 2;
const range = ref([startTime, endTime]);
const complateChartData = reactive({
  auto_follow:[],//自动跟机状态
  complete_automatic_push: [], // 完成自动推溜
  complete_automatic_rack_transfer: [], // 完成自动移架
  complete_automatic_care: [], // 完成自动收护帮板
  complete_automatic_extension: [], // 完成自动伸护帮板
});
const label_select = ref("0000-00-00 00:00:00");
const options = ref([]) 
const is_query = ref(false)




//获取时间戳，并发送查询http请求
const getAutoData = async () => {
 
  let { code, message } = await getAutoDataAPI({
    start_time: dayjs(range.value[0]).format("YYYY-MM-DD HH:mm:ss"),
    end_time: dayjs(range.value[1]).format("YYYY-MM-DD HH:mm:ss"),
  });
  if(code == 0){
    console.log("查询",message)
    options.value =[]
    for (var i=0;i<message.length;i++){
      options.value.push({
          label: dayjs(message[i]["time"]).format("YYYY-MM-DD HH:mm:ss") ,
          value: message[i]["id"],
          disabled: false
      })
    }
    console.log("查询",options.value[0]["label"])
    label_select.value = options.value[0]["label"]
    //options.a
    // complateChartData.auto_follow = message.is_auto_follow;
    // complateChartData.complete_automatic_push = message.complete_automatic_push;
    // complateChartData.complete_automatic_rack_transfer =message.complete_automatic_rack_transfer;
    // complateChartData.complete_automatic_care = message.complete_automatic_care;
    // complateChartData.complete_automatic_extension =message.complete_automatic_extension;
  }else if (code==2){
    nMessage.info(message);
  }else{
      nMessage.info("查询异常!");
  }
};

const onChange =(value)=>{
  //console.log("类型",typeof value[0])
  startTime= value[0]
  endTime= value[1]
  range.value = [value[0],value[1]]
  //console.log("日期选择器日期更新",value[0],dayjs(value[0]).format("YYYY-MM-DD HH:mm:ss"),dayjs(value[1]).format("YYYY-MM-DD HH:mm:ss"))
}

const handleUpdateTime = async(value) =>{

  is_query.value = true
  choose_id.value = value
  let { code, message } = await getOneAutoDataAPI({
    id: value,
  });
  //console.log("单一",code,message,choose_id.value)
  if (code==0){
    complateChartData.auto_follow = message.is_auto_follow;
    complateChartData.complete_automatic_push = message.complete_automatic_push;
    complateChartData.complete_automatic_rack_transfer =message.complete_automatic_rack_transfer;
    complateChartData.complete_automatic_care = message.complete_automatic_care;
    complateChartData.complete_automatic_extension =message.complete_automatic_extension;
  }else if (code==2){
    nMessage.info(message);
  }else{
      nMessage.info("查询异常!");
  }
 
}
const getNextAutoData = async() =>{
  let { code, message} = await getNextOneAutoDataAPI({
    id: choose_id.value,
  });
  console.log("下一条",code,message)
  if (code==0){
    complateChartData.auto_follow = message["action"].is_auto_follow;
    complateChartData.complete_automatic_push = message["action"].complete_automatic_push;
    complateChartData.complete_automatic_rack_transfer =message["action"].complete_automatic_rack_transfer;
    complateChartData.complete_automatic_care = message["action"].complete_automatic_care;
    complateChartData.complete_automatic_extension =message["action"].complete_automatic_extension;

    choose_id.value =  message["id"]
    label_select.value = dayjs(message["time"]).format("YYYY-MM-DD HH:mm:ss")

  }else if (code==2){
    nMessage.info(message);
  }else{
      nMessage.info("查询异常!");
  }
}

const getLastAutoData = async() =>{
  let { code, message} = await getLastOneAutoDataAPI({
    id: choose_id.value,
  });
  console.log("上一条",code,message)
  if (code==0){
    complateChartData.auto_follow = message["action"].is_auto_follow;
    complateChartData.complete_automatic_push = message["action"].complete_automatic_push;
    complateChartData.complete_automatic_rack_transfer =message["action"].complete_automatic_rack_transfer;
    complateChartData.complete_automatic_care = message["action"].complete_automatic_care;
    complateChartData.complete_automatic_extension =message["action"].complete_automatic_extension;

    choose_id.value =  message["id"]
    label_select.value = dayjs(message["time"]).format("YYYY-MM-DD HH:mm:ss")

  }else if (code==2){
    nMessage.info(message);
  }else{
      nMessage.info("查询异常!");
  }
}
onMounted( async() => {
  let {code,message} = await getSupportNum();
  counts.value = message
});

</script>

  
