<template>
  <div ref="charts" style="height:100%;width:100%"></div>
</template>

<script setup>
import * as echarts from "echarts";
import { onMounted, ref, watch } from "vue-demi";
const charts = ref(null);

const props = defineProps({
  count: Number,
  status: Object,
});
let chartDom;
let option = {
  grid: [
    { left: "2%", top: "17%", width: "95%", height: "5%" },
    { left: "2%", top: "34%", width: "95%", height: "5%" },
    { left: "2%", top: "51%", width: "95%", height: "5%" },
    { left: "2%", top: "68%", width: "95%", height: "5%" },
    { left: "2%", top: "85%", width: "95%", height: "5%" },
  ],
  xAxis: [
    {
      gridIndex: 0,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 1,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 2,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 3,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 4,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
  ],
  // xAxis: {
  //   type: "category",
  //   data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
  // },
  legend: {
    top: 18,
    textStyle: {
      fontSize: 15,
    },
    data: [],
  },
  tooltip: {
    trigger: "axis",
    axisPointer: {
      type: "shadow",
    },
    valueFormatter: (value) => "",
  },
  yAxis: [
    {
      gridIndex: 0,
      minInterval: 1,
      nameGap: 0,
      name: "自动跟机状态",
    },
    {
      gridIndex: 1,
      minInterval: 1,
      nameGap: 0,
      name: "伸护帮",
    },
    {
      gridIndex: 2,
      minInterval: 1,
      nameGap: 0,
      name: "收护帮",
    },
    {
      gridIndex: 3,
      nameGap: 0,
      minInterval: 1,
      name: "移架",
    },
    {
      gridIndex: 4,
      minInterval: 1,
      nameGap: 0,
      name: "推溜",
    },
  ],
  // yAxis: {
  //   type: "value",
  //   show: false,
  // },
  // series: [{ name: props.name, data: [], type: "bar" }],
  series: [
  {
      name: "自动跟机",
      type: "bar",
      xAxisIndex: 0,
      yAxisIndex: 0,
      itemStyle: {
        color: "#4FD000",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },

      data: [],
    },
 
    {
      name: "伸护帮",
      type: "bar",
      xAxisIndex: 1,
      yAxisIndex: 1,
      itemStyle: {
        color: "#4FD000",
      },
      lineStyle: {
        color: "#555",
        width: 3,
      },
      animationDelay: function (idx) {
        return idx * 5;
      },
      data: [],
    },
    {
      name: "收护帮",
      type: "bar",
      xAxisIndex: 2,
      yAxisIndex: 2,
      itemStyle: {
        color: "#4FD000",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },
      markLine: {},
      data: [],
    },
    {
      name: "移架",
      type: "bar",
      xAxisIndex: 3,
      yAxisIndex: 3,
      itemStyle: {
        color: "#4FD000",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },
      markLine: {},
      data: [],
    },
    {
      name: "推溜",
      type: "bar",
      xAxisIndex: 4,
      yAxisIndex: 4,
      itemStyle: {
        color: "#4FD000",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },

      data: [],
    },
  ],
};
const reDraw = () => {
  // option.series[0].data = [1, 1, 1, 1, 1, 1];
  chartDom.setOption(option);
  chartDom.resize();
};

watch(
  () => props.count,
  (val) => {
    console.log("监听到值的变化",props.count)


    option.xAxis =  [
    {
      gridIndex: 0,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 1,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 2,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 3,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 4,
      min: 0,
      data: Array.from({ length: val}).map((v, k) => k + 1 + "架"),
    },
  ]
  chartDom.setOption(option);
  chartDom.resize();
  }
);


watch(
  () => props.status,
  (val) => {
   // console.log("监听到状态变化",typeof val.auto_follow ,val.auto_follow.length,val.auto_follow[197])
    if (
      typeof val.auto_follow == "object" &&
      val.auto_follow.length > 0
    ) {
      let data = [];
      for (
        let index = 0;
        index < val.auto_follow.length;
        index++
      ) {
        const element = val.auto_follow[index];
        if (element == 0) {
          data.push(0);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#0000a9",
            },
          });
        }
      }
      option.series[0].data = data;
    }
    if (
      typeof val.complete_automatic_extension == "object" &&
      val.complete_automatic_extension.length > 0
    ) {
      let data = [];
      for (
        let index = 0;
        index < val.complete_automatic_extension.length;
        index++
      ) {
        const element = val.complete_automatic_extension[index];
        if (element == 0) {
          data.push(0);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#0000a9",
            },
          });
        }
      }
      option.series[1].data = data;
    }
    if (
      typeof val.complete_automatic_care == "object" &&
      val.complete_automatic_care.length > 0
    ) {
      let data = [];
      for (let index = 0; index < val.complete_automatic_care.length; index++) {
        const element = val.complete_automatic_care[index];
        if (element == 0) {
          data.push(0);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#0000a9",
            },
          });
        }
      }
      option.series[2].data = data;
    }
    if (
      typeof val.complete_automatic_rack_transfer == "object" &&
      val.complete_automatic_rack_transfer.length > 0
    ) {
      let data = [];
      for (
        let index = 0;
        index < val.complete_automatic_rack_transfer.length;
        index++
      ) {
        const element = val.complete_automatic_rack_transfer[index];
        if (element == 0) {
          data.push(0);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#0000a9",
            },
          });
        }
      }
      option.series[3].data = data;
    }
    if (
      typeof val.complete_automatic_push == "object" &&
      val.complete_automatic_push.length > 0
    ) {
      let data = [];
      for (let index = 0; index < val.complete_automatic_push.length; index++) {
        const element = val.complete_automatic_push[index];
        if (element == 0) {
          data.push(0);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#0000a9",
            },
          });
        }
      }
      option.series[4].data = data;
    }
    chartDom.setOption(option);
    chartDom.resize();
  },
  {
    deep: true,
  }
);
onMounted(() => {
  console.log("charts.value",charts.value)
  chartDom = echarts.init(charts.value);
  reDraw();
});
</script>

